import numpy as np
def f(n, b):
    if n == 0: return 1
    d = []
    t = abs(n)
    while t > 0:
        d.append(t % b)
        t //= b
    return len(d)
def r(n, b):
    if n == 0: return 0
    return 1 + ((n - 1) % (b - 1))
def s(m=19):
    o = []
    for b in range(2, m + 1):
        v = [1]
        for i in range(2, b):
            k_max = int(np.floor(1 / (1 - (np.log(i) / np.log(b)))))
            for k in range(1, k_max + 1):
                n = int(i**k)
                if f(n, b) == k and r(n, b) == i:
                    v.append(n)
        o.append(str(max(v)))
    print(", ".join(o))
s(19)

